question:
What will be the output of the following Python code snippet?

for i in [1, 2, 3, 4][::-1]:
    print(i, end=' ')

What will the following code output?
for i in range(3):
    print(i)

What is the output of the following code?

value = ''
if value:
    print('truthy')
else:
    print('falsy')

What does the following code print?

x = 0
if x:
    print('yes')
elif not x:
    print('no')
else:
    print('maybe')

What is the output of the following code?

my_list = []
if my_list:
    print('has items')
else:
    print('empty')

What is the output of the following code?

a = 5
b = 10
if a > 3 and b < 8:
    print('X')
elif a > 3 and b > 8:
    print('Y')
else:
    print('Z')

What is the output of the following code?

x = None
if x:
    print(1)
elif x is None:
    print(2)
else:
    print(3)

What is the output of the following code?

for i in range(3):
    if i == 1:
        print('one')
    else:
        print('other')

What is the output of the following code?

data = {'key': False}
if data:
    print('dict is truthy')
if data['key']:
    print('value is truthy')
else:
    print('value is falsy')

What is the output of the following code?

for i in range(3):
    print(i)

What is the output of the following code?

for i in range(5):
    if i == 3:
        break
    print(i)

What is the output of the following code?

for i in range(5):
    if i == 3:
        continue
    print(i)

What does the else clause on a for loop do?

for i in range(3):
    pass
else:
    print('done')

What is the output of the following code?

for i in range(4):
    if i == 2:
        break
else:
    print('no break')

What is the output of the following code?

for i in range(2, 8, 2):
    print(i, end=' ')

What is the output of the following code?

for i in range(3):
    for j in range(2):
        if j == 1:
            break
    print(i)

What is the output of the following code?

for letter in 'cat':
    print(letter)

What is the output of the following code?

s1 = {1, 2, 3, 4}
s2 = {3, 4, 5, 6}
print(s1 - s2)

Which of the following correctly describes the behavior of s1 ^= s2 for two sets?

s1 = {1, 2, 3}
s2 = {2, 3, 4}
s1 ^= s2
print(s1)

What is the output of the following code?

a = {1, 2, 3}
b = {1, 2, 3, 4, 5}
print(a < b, a <= b)

What is the output of the following code?

s = {3, 1, 4, 1, 5, 9, 2, 6}
print(len(s))

What is the output of the following code?

s = {1, 2, 3}
t = s
s |= {4, 5}
print(t)

Which of the following will raise a TypeError?

A. my_set = {frozenset({1, 2}), frozenset({3, 4})}
B. my_set = {{1, 2}, {3, 4}}
C. my_set = {(1, 2), (3, 4)}
D. my_set = frozenset({frozenset({1}), frozenset({2})})

What is wrong with this code?

d = {'a': 1, 'b': 2}
for key in d:
    if d[key] == 1:
        del d[key]

What is the output of the following code?

d = {'a': 1, 'b': 2}
print(d.get('c', 0), d.get('a', 0))

What is the output of the following code?

d = {'a': 1, 'b': 2, 'c': 3}
print(list(d.keys())[-1])

What is the output of the following code?

d = {'a': 1, 'b': 2}
result = {**d, 'b': 99, 'c': 3}
print(result['b'], 'a' in result)
